for (const item of $input.all()) {
  const question = $('Luận giải tarot').first().json.body.question || "";
  const cards = $('Luận giải tarot').first().json.body.cards || [];
  const userProfile = $('Luận giải tarot').first().json.body.userProfile || { name: 'lữ khách', gender: 'bạn' };
  const userName = userProfile.name;
  const userGender = userProfile.gender;
  const readerPrompt = $('Luận giải tarot').first().json.body.reader_prompt || '';

  let isFollowUp = false;
  let previousQuestions = [];
  let historyText = "Chưa có.";

  // Lấy mảng history do Astro Webhook truyền sang
  const history = $('Luận giải tarot').first().json.body.history || [];

  if (history.length > 0) {
    isFollowUp = true;

    // Lọc ra các câu hỏi của user từ mảng history
    previousQuestions = history.filter(msg => msg.role === 'user').map(msg => msg.content);

    if (previousQuestions.length > 0) {
      const questionsStr = previousQuestions.map((q, i) => `Lần ${i+1}: "${q}"`).join('\n');
      historyText = `Các câu hỏi trước đó:\n${questionsStr}`;
    }
  }

  // Prompt mặc định (dùng khi không có reader_prompt)
  const defaultFirstPrompt = `## ROLE: Master Tarot Reader
## TASK: Hóa thân thành một Tarot Reader sâu sắc, ấm áp, thấu cảm và chuyên nghiệp sử dụng bộ bài Rider–Waite. Giải đáp câu hỏi dựa trên các lá bài đã bốc.`;
  const defaultFollowUpPrompt = `## ROLE: Master Tarot Reader
## TASK: Hóa thân thành một Tarot Reader sâu sắc, ấm áp. Lữ khách vừa bốc thêm 3 lá bài mới. Trực tiếp luận giải 3 lá bài MỚI này.`;

  // Dùng reader_prompt nếu có, fallback về default tương ứng
  const narrativeBase = readerPrompt || (isFollowUp ? defaultFollowUpPrompt : defaultFirstPrompt);

  let mySystemPrompt = "";
  if (!isFollowUp) {
    mySystemPrompt = narrativeBase + `

## USER INFO: Tên: ${userName}, Xưng hô: ${userGender}. Hãy gọi tên và xưng hô tự nhiên như một người bạn tâm giao.

## HƯỚNG DẪN LUẬN GIẢI:
1. Kết nối ý nghĩa của 3 lá bài theo tiến trình thời gian (Quá khứ → Hiện tại → Tương lai) để tạo nên một câu chuyện mạch lạc.
2. Lồng ghép cả "mặt sáng" và "bài học cần học", tuyệt đối không mê tín dị đoan.
3. Giọng văn con người trầm ổn, đồng cảm.
4. KHÔNG nhắc đến AI, thuật toán, máy tính, ngẫu nhiên hoặc "Xuôi". (Dùng từ: Hướng thuận, mặt thuận lợi...).
5. Trình bày đẹp mắt bằng Markdown. Dưới 1000 tokens.

## CẤU TRÚC BẮT BUỘC:
---
Lời chào mở đầu (1–2 câu)
### 1. Mở đầu và cảm nhận chung (2-3 câu)
### 2. Dòng chảy của câu chuyện (Quá khứ → Hiện tại → Tương lai) (3-4 câu)
### 3. Sự kết nối giữa các lá bài (3-4 câu)
### 4. Lời khuyên từ trái tim (2-3 câu)
→ Kết thúc bằng 1–2 câu hỏi tự vấn`;
  } else {
    mySystemPrompt = narrativeBase + `

## USER INFO: Tên: ${userName}, Xưng hô: ${userGender}. Hãy gọi tên và xưng hô tự nhiên.

## HƯỚNG DẪN LUẬN GIẢI:
1. TRỰC TIẾP đi vào luận giải 3 lá bài mới, KHÔNG lặp lại lời chào sến súa. Nhắc đến tên lá bài để lữ khách biết bạn đang giải bài mới.
2. Trình bày linh hoạt, tự nhiên như trò chuyện. KHÔNG theo outline rập khuôn.
3. Ngắt đoạn linh hoạt, dùng bullet points tự do.
4. Trọng tâm là 3 lá MỚI. Liên kết nhẹ nhàng với bối cảnh trước đó. Tuân thủ ý nghĩa gốc.
5. Giọng văn trầm ổn. TUYỆT ĐỐI KHÔNG nhắc đến AI, thuật toán.`;
  }

  let cardsSection = "";
  if (cards.length > 0) {
    const cardPast = cards[0] || {};
    const cardPresent = cards[1] || {};
    const cardFuture = cards[2] || {};
    cardsSection = `### [LÁ BÀI & Ý NGHĨA]
- Lá 1(Quá khứ): ${cardPast.name || "?"} (${cardPast.orientation || "Xuôi"}) - ${cardPast.meaning || "?"}
- Lá 2(Hiện tại): ${cardPresent.name || "?"} (${cardPresent.orientation || "Xuôi"}) - ${cardPresent.meaning || "?"}
- Lá 3(Tương lai): ${cardFuture.name || "?"} (${cardFuture.orientation || "Xuôi"}) - ${cardFuture.meaning || "?"}`;
  }

  const myUserPrompt = `### [CÂU HỎI MỚI]
"${question}"

${cardsSection}

### [BỐI CẢNH TRƯỚC ĐÓ]
${historyText}

Giải đáp thấu cảm.`;

  item.json.bodyPayload = {
    model: "n8n2",
    messages: [
      { role: "system", content: mySystemPrompt },
      { role: "user", content: myUserPrompt }
    ],
    temperature: 0.7
  };
}

return $input.all();

